  /*rsvpArray = rsvpArray.map(obj => ({
    ...obj,
    quizAnswer: 200,
    children: null
  }));*/

  try {
    const res = await fetch(`${API_URL}/api/rsvps/batch`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(personOption),
    });

    if (res.ok) {
      console.log(res)
    } else {
